import { z } from 'zod';

const envSchema = z.object({
  NODE_ENV: z.enum(['development', 'production', 'test']),
  PORT: z.string(),
  MONGODB_URI: z.string().url(),
  JWT_SECRET: z.string(),
  TELEGRAM_BOT_TOKEN: z.string(),
  TELEGRAM_CHAT_ID: z.string()
});

envSchema.parse(process.env);

export const env = envSchema.safeParse(process.env);

import cron from 'node-cron';
import { TaskService } from '../services/task-service';
import { NotificationService } from '../services/notification-service';
import { env } from '../config/env';

export class SchedulingEngine {
  private taskService: TaskService;
  private notificationService: NotificationService;

  constructor() {
    this.taskService = new TaskService();
    this.notificationService = new NotificationService();

    cron.schedule('*/1 * * * *', async () => {
      // Run every minute
      const tasks = await this.taskService.getPendingTasks(new Date());
      tasks.forEach(task => {
        this.notificationService.notify(task);
      });
    }, {
      timezone: 'Asia/Ho_Chi_Minh'  // UTC+7 as required
    });
  }
}

import { TaskRepository } from '../repositories/task-repository';
import { Task } from '../dtos/task-dto';

export class TaskService {
  private taskRepository: TaskRepository;

  constructor() {
    this.taskRepository = new TaskRepository();
  }

  public async getPendingTasks(date: Date): Promise<Task[]> {
    return await this.taskRepository.findPendingTasks(date);
  }
}

import { NotificationLogRepository } from '../repositories/notification-log-repository';
import { Task } from '../dtos/task-dto';
import { Logger } from '../utils/logger';

export class NotificationService {
  private notificationLogRepository: NotificationLogRepository;
  private logger: Logger;

  constructor() {
    this.notificationLogRepository = new NotificationLogRepository();
    this.logger = new Logger();
  }

  public notify(task: Task): void {
    try {
      // Mocking notification process
      console.log(`Notify task: ${task.title} to assignees.`);
      this.notificationLogRepository.createLog(task.id, 'success');
    } catch (error) {
      this.logger.error('Notification failed', {
        taskId: task.id,
        errorDetails: error
      });
      this.notificationLogRepository.createLog(task.id, 'failed', error);
    }
  }
}

import { createLogger, format, transports } from 'winston';

export class Logger {
  private logger = createLogger({
    level: 'info',
    format: format.combine(
      format.timestamp({ format: 'YYYY-MM-DD HH:mm:ss' }),
      format.errors({ stack: true }),
      format.json()
    ),
    defaultMeta: { service: 'scheduling-engine' },
    transports: [
      new transports.Console()
    ]
  });

  public info(message: string, meta?: Record<string, unknown>): void {
    this.logger.info(message, meta);
  }

  public error(message: string, meta?: Record<string, unknown>): void {
    this.logger.error(message, meta);
  }
}

import { Task } from '../dtos/task-dto';
import { mongoose } from 'mongoose';

export class TaskRepository {
  // Assuming TaskModel is a mongoose model
  private taskModel = mongoose.model<Task>('Task');

  public async findPendingTasks(currentTime: Date): Promise<Task[]> {
    return this.taskModel.find({
      'recurrence.time': { $lte: currentTime },
      status: 'active'
    });
  }
}
